1	/**
2	 * Zustand store for synthesizer state.
3	 * Per-instrument-track synth parameter state, serializable.
4	 */
5	
6	import { create } from "zustand";
7	import {
8	  DEFAULT_SYNTH_PARAMS,
9	  type SynthParameterMap,
10	} from "@audio/synth/synth-types";
11	
12	export type SynthTrackState = {
13	  readonly trackId: string;
14	  readonly params: SynthParameterMap;
15	  readonly legato: boolean;
16	};
17	
18	export type SynthStore = {
19	  /** Per-track synth state keyed by track ID */
