1	/**
2	 * SynthInstrument: main-thread controller for the synth AudioWorklet.
3	 * Creates AudioWorkletNode, sends voice commands, manages parameters,
4	 * connects output to mixer channel strip.
5	 *
6	 * R-EVT-08: Real-time parameter changes via MessagePort.
7	 */
8	
9	import type { SynthVoiceCommand, SynthParameterMap } from "./synth-types";
10	import {
11	  DEFAULT_SYNTH_PARAMS,
12	  WAVEFORM_TYPES,
13	  FILTER_TYPES,
14	  LFO_SHAPES,
15	} from "./synth-types";
16	import type { MixerEngine } from "@audio/mixer/types";
17	
18	export type SynthInstrument = {
19	  /** The audio output node — connect to mixer channel strip. */
20	  readonly output: AudioNode;
21	  /** Current parameter values. */
22	  readonly params: Readonly<SynthParameterMap>;
23	  /** Send a note-on to the synth. */
24	  noteOn(note: number, velocity: number, legato?: boolean): void;
25	  /** Send a note-off to the synth. */
26	  noteOff(note: number): void;
27	  /** Release all notes. */
28	  allNotesOff(): void;
29	  /** Set a synth parameter (forwarded to worklet). */
30	  setParam<K extends keyof SynthParameterMap>(
31	    key: K,
32	    value: SynthParameterMap[K],
33	  ): void;
34	  /** Connect to a mixer channel. */
35	  connectToMixer(mixer: MixerEngine, trackId: string): void;
36	  /** Disconnect from mixer. */
37	  disconnectFromMixer(mixer: MixerEngine, trackId: string): void;
38	  /** Clean up all resources. */
39	  dispose(): void;
40	};
41	
42	/** URL for the worklet processor module */
43	const PROCESSOR_URL = new URL("./synth-processor.ts", import.meta.url);
44	
45	/**
46	 * Create a SynthInstrument connected to the given AudioContext.
47	 * Must call `audioCtx.audioWorklet.addModule()` first via loadWorkletModule().
48	 */
49	export async function createSynthInstrument(
50	  ctx: AudioContext,
51	): Promise<SynthInstrument> {
52	  // Load the worklet module
53	  await ctx.audioWorklet.addModule(PROCESSOR_URL.href);
54	
55	  const node = new AudioWorkletNode(ctx, "synth-processor", {
56	    numberOfInputs: 0,
57	    numberOfOutputs: 1,
58	    outputChannelCount: [2],
59	  });
60	
61	  const params: SynthParameterMap = { ...DEFAULT_SYNTH_PARAMS };
62	
63	  function postCommand(cmd: SynthVoiceCommand): void {
64	    node.port.postMessage(cmd);
65	  }
66	
67	  const instrument: SynthInstrument = {
68	    output: node,
69	    params,
70	
71	    noteOn(note: number, velocity: number, legato = false): void {
72	      postCommand({ type: "noteOn", note, velocity, legato });
73	    },
74	
75	    noteOff(note: number): void {
76	      postCommand({ type: "noteOff", note });
77	    },
78	
79	    allNotesOff(): void {
80	      postCommand({ type: "allNotesOff" });
81	    },
82	
83	    setParam<K extends keyof SynthParameterMap>(
84	      key: K,
85	      value: SynthParameterMap[K],
86	    ): void {
87	      (params as Record<string, unknown>)[key] = value;
88	
89	      // Map enum types to numeric index for the worklet
90	      let numericValue: number;
91	      if (typeof value === "string") {
92	        // Lookup string in appropriate type array
93	        switch (key) {
94	          case "osc1Type":
95	          case "osc2Type":
96	            numericValue = WAVEFORM_TYPES.indexOf(
97	              value as (typeof WAVEFORM_TYPES)[number],
98	            );
99	            break;
100	          case "filterType":
101	            numericValue = FILTER_TYPES.indexOf(
102	              value as (typeof FILTER_TYPES)[number],
103	            );
104	            break;
105	          case "lfo1Shape":
106	          case "lfo2Shape":
107	            numericValue = LFO_SHAPES.indexOf(
108	              value as (typeof LFO_SHAPES)[number],
109	            );
110	            break;
111	          default:
112	            numericValue = 0;
113	        }
114	      } else {
115	        numericValue = value;
116	      }
117	
118	      postCommand({
119	        type: "setParam",
120	        key: key as string,
121	        value: numericValue,
122	      });
123	    },
124	
125	    connectToMixer(mixer: MixerEngine, trackId: string): void {
126	      const strip = mixer.getOrCreateStrip(trackId);
127	      node.connect(strip.inputGain);
128	    },
129	
130	    disconnectFromMixer(_mixer: MixerEngine, _trackId: string): void {
131	      node.disconnect();
132	    },
133	
134	    dispose(): void {
135	      node.disconnect();
136	      node.port.close();
137	    },
138	  };
139	
140	  return instrument;
141	}
142

