270	    const osc1DetMul = Math.pow(2, p.osc1Detune / 1200);
271	    const osc2OctMul = Math.pow(2, p.osc2Octave);
272	    const osc2DetMul = Math.pow(2, p.osc2Detune / 1200);
273	
274	    for (let s = 0; s < numSamples; s++) {
275	      const lfo1Val = this.lfo1.process(p.lfo1Rate, sr);
276	      const lfo2Val = this.lfo2.process(p.lfo2Rate, sr);
277	
278	      let mixL = 0;
279	      let mixR = 0;
280	
281	      for (let vi = 0; vi < MAX_VOICES; vi++) {
282	        const voice = at(this.allocator.voices as unknown[], vi) as {
283	          state: string;
284	          stealFadeGain: number;
285	        };
286	
287	        // S2-5: Early idle check before any DSP work
288	        if (voice.state === "idle") continue;
289	
290	        const vd = at(this.voiceData, vi);
291	
292	        // Check if envelope finished release — mark idle before processing
293	        if (vd.ampEnv.stage === "idle" && voice.state === "releasing") {
294	          this.allocator.markIdle(vi);
295	          continue;
296	        }
297	
298	        // Pitch glide (R-STA-05)
299	        if (p.glideTime > 0 && vd.currentFreq !== vd.targetFreq) {
300	          const glideCoeff = 1 - Math.exp(-1 / (p.glideTime * sr));
301	          vd.currentFreq += glideCoeff * (vd.targetFreq - vd.currentFreq);
302	        } else {
303	          vd.currentFreq = vd.targetFreq;
304	        }
305	
306	        const baseFreq = vd.currentFreq;
307	
308	        // LFO1 -> pitch modulation (in semitones)
309	        const pitchMod = lfo1Val * p.lfo1Depth * 2;
310	        const pitchMultiplier = Math.pow(2, pitchMod / 12);
311	
312	        const freq1 = baseFreq * osc1OctMul * osc1DetMul * pitchMultiplier;
313	        const freq2 = baseFreq * osc2OctMul * osc2DetMul * pitchMultiplier;
314	
315	        const osc1Out = vd.osc1.next(freq1, sr) * p.osc1Level;
316	        const osc2Out = vd.osc2.next(freq2, sr) * p.osc2Level;
317	        let sample = osc1Out + osc2Out;
318	
319	        // Filter envelope (must process every sample to advance state)
320	        const filterEnvVal = vd.filterEnv.process(this.filterParams, sr);
321	
322	        // Control-rate filter coefficients: recompute once per block per voice
323	        // (avoids expensive Math.sin/cos per-sample; block rate ~3ms at 44.1kHz)
324	        if (s === 0) {
325	          const envCutoffMod = filterEnvVal * p.filterEnvDepth;
326	          const lfoCutoffMod = lfo1Val * p.lfo1Depth * 12;
327	          const velCutoffMod = vd.velocity * 24;
328	          const totalCutoffMod = envCutoffMod + lfoCutoffMod + velCutoffMod;
329	          const modulatedCutoff =
330	            p.filterCutoff * Math.pow(2, totalCutoffMod / 12);
331	          const clampedCutoff = Math.min(
332	            Math.max(modulatedCutoff, 20),
333	            sr / 2 - 100,
334	          );
335	          computeBiquadCoeffs(
336	            p.filterType,
337	            clampedCutoff,
338	            p.filterResonance,
339	            sr,
340	            vd.filter.coeffs,
341	          );
342	        }
343	
344	        sample = vd.filter.process(sample);
345	
346	        // Amplitude envelope
347	        const ampLevel = vd.ampEnv.process(this.ampParams, sr);
348	
349	        // LFO2 -> amplitude modulation (tremolo)
350	        const ampMod = 1 + lfo2Val * p.lfo2Depth * 0.5;
351	
352	        // Velocity -> amplitude
353	        const velAmp = 0.5 + vd.velocity * 0.5;
354	
355	        sample *= ampLevel * ampMod * velAmp * p.masterGain;
356	
357	        // S1-2: Apply steal crossfade gain to old voice audio
358	        if (voice.state === "stealing") {
359	          sample *= voice.stealFadeGain;
360	        }
361	
362	        mixL += sample;
363	        mixR += sample;
364	      }
365	
366	      // Process steal fades and get completed steals
367	      const completed = this.allocator.processStealFade(sr);
368	
369	      // S1-3: Apply pending notes for voices that completed steal crossfade
370	      for (let ci = 0; ci < completed.count; ci++) {
371	        const completedIdx = completed.data[ci];
372	        if (completedIdx !== undefined) {
373	          const voice = at(
374	            this.allocator.voices as unknown[],
375	            completedIdx,
376	          ) as {
377	            note: number;
378	            velocity: number;
379	          };
380	          this.applyNoteOn(completedIdx, voice.note, voice.velocity, false);
381	        }
382	      }
383	
384	      outL[s] = mixL;
385	      outR[s] = mixR;
386	    }
387	
388	    return this.alive;
389	  }
390	}
391	
392	registerProcessor("synth-processor", SynthProcessor);
