  private applyNoteOn(
    idx: number,
    note: number,
    velocity: number,
    legato: boolean,
  ): void {
    const vd = at(this.voiceData, idx);

    const baseFreq = midiToFreq(note);
    vd.targetFreq = baseFreq;
    vd.velocity = velocity / 127;

    if (!legato || vd.currentFreq === 0) {
      vd.currentFreq = baseFreq;
