1	/**
2	 * Modulation engine: pure, zero-allocation functions for computing
3	 * modulation offsets from routes. Used inside the AudioWorklet processor.
4	 *
5	 * Design: Pre-allocated accumulators are reset each quantum, then
6	 * each active route adds source * amount to its destination accumulator.
7	 * The processor reads accumulators to offset synth parameters.
8	 */
9	
10	// ─── Source and destination index maps (numeric for worklet) ───
11	
12	export const SOURCE_INDEX = {
13	  lfo1: 0,
14	  lfo2: 1,
15	  ampEnv: 2,
16	  filterEnv: 3,
17	  velocity: 4,
18	  aftertouch: 5,
19	  modWheel: 6,
20	  pitchBend: 7,
21	} as const;
22	
23	export const DEST_INDEX = {
24	  osc1Pitch: 0,
25	  osc2Pitch: 1,
26	  oscMix: 2,
27	  filterCutoff: 3,
28	  filterResonance: 4,
29	  ampLevel: 5,
30	  lfo1Rate: 6,
31	  lfo2Rate: 7,
32	} as const;
33	
34	// ─── Accumulators ───
35	
36	export type ModAccumulators = {
37	  osc1Pitch: number;
38	  osc2Pitch: number;
39	  oscMix: number;
40	  filterCutoff: number;
41	  filterResonance: number;
42	  ampLevel: number;
43	  lfo1Rate: number;
44	  lfo2Rate: number;
45	};
46	
47	export function createModAccumulators(): ModAccumulators {
48	  return {
49	    osc1Pitch: 0,
50	    osc2Pitch: 0,
51	    oscMix: 0,
52	    filterCutoff: 0,
53	    filterResonance: 0,
54	    ampLevel: 0,
55	    lfo1Rate: 0,
56	    lfo2Rate: 0,
57	  };
58	}
59	
60	export function resetAccumulators(acc: ModAccumulators): void {
61	  acc.osc1Pitch = 0;
62	  acc.osc2Pitch = 0;
63	  acc.oscMix = 0;
64	  acc.filterCutoff = 0;
65	  acc.filterResonance = 0;
66	  acc.ampLevel = 0;
67	  acc.lfo1Rate = 0;
68	  acc.lfo2Rate = 0;
69	}
70	
71	// Dest keys indexed by DEST_INDEX values for fast lookup
72	const DEST_KEYS: readonly (keyof ModAccumulators)[] = [
73	  "osc1Pitch",
74	  "osc2Pitch",
75	  "oscMix",
76	  "filterCutoff",
77	  "filterResonance",
78	  "ampLevel",
79	  "lfo1Rate",
80	  "lfo2Rate",
81	];
82	
83	/**
84	 * Apply a single modulation route to accumulators.
85	 * Zero-allocation: reads from pre-allocated sourceValues array,
86	 * writes to pre-allocated accumulators object.
87	 */
88	export function applyModRoute(
89	  acc: ModAccumulators,
90	  sourceValues: Float64Array,
91	  sourceIdx: number,
92	  destIdx: number,
93	  amount: number,
94	  bipolar: boolean,
95	): void {
96	  const raw = sourceValues[sourceIdx] ?? 0;
97	  const value = bipolar ? raw : (raw + 1) / 2;
98	  const key = DEST_KEYS[destIdx];
99	  if (key !== undefined) {
100	    acc[key] += value * amount;
101	  }
102	}
103	
104	// ─── Serialized route format for worklet MessagePort ───
105	
106	export type WorkletModRoute = {
107	  sourceIdx: number;
108	  destIdx: number;
109	  amount: number;
110	  bipolar: boolean;
111	};
112

1	/**
2	 * Zustand store for modulation matrix state.
3	 * Per-track modulation routes, serializable for session persistence.
4	 */
5	
6	import { create } from "zustand";
7	import {
8	  createModRoute,
9	  MAX_MOD_ROUTES,
10	  type ModRoute,
11	  type ModSource,
12	  type ModDestination,
13	  MOD_SOURCES,
14	  MOD_DESTINATIONS,
15	} from "@audio/synth/modulation-types";
16	import {
17	  SOURCE_INDEX,
18	  DEST_INDEX,
19	  type WorkletModRoute,
20	} from "@audio/synth/modulation-engine";
21	
22	type TrackModMatrix = {
23	  readonly routes: readonly ModRoute[];
24	};
25	
26	export type ModulationStore = {
27	  matrices: Record<string, TrackModMatrix>;
28	
29	  initMatrix: (trackId: string) => void;
30	  removeMatrix: (trackId: string) => void;
31	  addRoute: (
32	    trackId: string,
33	    source: ModSource,
34	    destination: ModDestination,
35	    amount?: number,
36	    bipolar?: boolean,
37	  ) => void;
38	  removeRoute: (trackId: string, routeId: string) => void;
39	  updateRouteAmount: (trackId: string, routeId: string, amount: number) => void;
40	  getRoutes: (trackId: string) => readonly ModRoute[];
41	  getWorkletRoutes: (trackId: string) => WorkletModRoute[];
42	};
43	
44	export const useModulationStore = create<ModulationStore>()((set, get) => ({
45	  matrices: {},
46	
47	  initMatrix(trackId) {
48	    set((s) => {
49	      if (s.matrices[trackId]) return s;
50	      return {
51	        matrices: {
52	          ...s.matrices,
53	          [trackId]: { routes: [] },
54	        },
55	      };
56	    });
57	  },
58	
59	  removeMatrix(trackId) {
60	    set((s) => {
61	      if (!s.matrices[trackId]) return s;
62	      return {
63	        matrices: Object.fromEntries(
64	          Object.entries(s.matrices).filter(([k]) => k !== trackId),
65	        ),
66	      };
67	    });
68	  },
69	
70	  addRoute(trackId, source, destination, amount = 0, bipolar = true) {
71	    set((s) => {
72	      const matrix = s.matrices[trackId];
73	      if (!matrix) return s;
74	      if (matrix.routes.length >= MAX_MOD_ROUTES) return s;
75	      const route = createModRoute(source, destination, amount, bipolar);
76	      return {
77	        matrices: {
78	          ...s.matrices,
79	          [trackId]: { routes: [...matrix.routes, route] },
80	        },
81	      };
82	    });
83	  },
84	
85	  removeRoute(trackId, routeId) {
86	    set((s) => {
87	      const matrix = s.matrices[trackId];
88	      if (!matrix) return s;
89	      return {
90	        matrices: {
91	          ...s.matrices,
92	          [trackId]: {
93	            routes: matrix.routes.filter((r) => r.id !== routeId),
94	          },
95	        },
96	      };
97	    });
98	  },
99	
100	  updateRouteAmount(trackId, routeId, amount) {
101	    const clamped = Math.max(-1, Math.min(1, amount));
102	    set((s) => {
103	      const matrix = s.matrices[trackId];
104	      if (!matrix) return s;
105	      return {
106	        matrices: {
107	          ...s.matrices,
108	          [trackId]: {
109	            routes: matrix.routes.map((r) =>
110	              r.id === routeId ? { ...r, amount: clamped } : r,
111	            ),
112	          },
113	        },
114	      };
115	    });
116	  },
117	
118	  getRoutes(trackId) {
119	    return get().matrices[trackId]?.routes ?? [];
120	  },
121	
122	  getWorkletRoutes(trackId) {
123	    const routes = get().matrices[trackId]?.routes ?? [];
124	    return routes.map((r) => ({
125	      sourceIdx: SOURCE_INDEX[r.source],
126	      destIdx: DEST_INDEX[r.destination],
127	      amount: r.amount,
128	      bipolar: r.bipolar,
129	    }));
130	  },
131	}));
132	
133	/** Source display labels */
134	export const MOD_SOURCE_LABELS: Record<ModSource, string> = {
135	  lfo1: "LFO 1",
136	  lfo2: "LFO 2",
137	  ampEnv: "Amp Env",
138	  filterEnv: "Filter Env",
139	  velocity: "Velocity",
140	  aftertouch: "Aftertouch",
141	  modWheel: "Mod Wheel",
142	  pitchBend: "Pitch Bend",
143	};
144	
145	/** Destination display labels */
146	export const MOD_DEST_LABELS: Record<ModDestination, string> = {
147	  osc1Pitch: "Osc 1 Pitch",
148	  osc2Pitch: "Osc 2 Pitch",
149	  oscMix: "Osc Mix",
150	  filterCutoff: "Filter Cutoff",
151	  filterResonance: "Filter Reso",
152	  ampLevel: "Amp Level",
153	  lfo1Rate: "LFO 1 Rate",
154	  lfo2Rate: "LFO 2 Rate",
155	};
156	
157	// Re-export for convenience
158	export { MOD_SOURCES, MOD_DESTINATIONS };
159

