1	/**
2	 * Synthesizer AudioWorklet processor.
3	 * Runs on the audio rendering thread — zero allocations in process().
4	 *
5	 * Architecture: 16 fixed voices, each with:
6	 * - 2 PolyBLEP oscillators
7	 * - Biquad filter (LP/HP/BP)
8	 * - ADSR amplitude envelope
9	 * - ADSR filter envelope
10	 * Shared: 2 LFOs, hardwired modulation matrix.
11	 *
12	 * INV-3/NFR-14: Zero-allocation process().
13	 * MIT-H4-5: Oldest-steal with 5ms crossfade.
14	 * MIT-H4-6: 2ms minimum release time.
15	 * R-STA-05: Legato mode with pitch glide.
16	 */
17	
18	import { createPolyBLEPOsc, type PolyBLEPOsc } from "./dsp/polyblep";
19	import {
20	  createADSREnvelope,
21	  type ADSREnvelope,
22	  type ADSRParams,
23	} from "./dsp/adsr";
24	import {
25	  computeBiquadCoeffs,
26	  createBiquadFilter,
27	  type BiquadFilter,
28	} from "./dsp/biquad-coeffs";
29	import { createLFO, type LFO } from "./dsp/lfo";
30	import {
31	  createVoiceAllocator,
32	  type VoiceAllocator,
33	  MAX_VOICES,
34	} from "./dsp/voice-allocator";
35	import {
36	  midiToFreq,
37	  WAVEFORM_TYPES,
38	  FILTER_TYPES,
39	  LFO_SHAPES,
40	  type SynthVoiceCommand,
41	  type SynthParameterMap,
42	  DEFAULT_SYNTH_PARAMS,
43	} from "./synth-types";
44	import {
45	  createModAccumulators,
46	  resetAccumulators,
47	  applyModRoute,
48	  type ModAccumulators,
49	  type WorkletModRoute,
50	  SOURCE_INDEX,
51	} from "./modulation-engine";
52	
53	// ─── AudioWorklet globals ───
54	declare const sampleRate: number;
55	declare class AudioWorkletProcessor {
56	  readonly port: MessagePort;
57	  constructor();
58	  process(
59	    inputs: Float32Array[][],
60	    outputs: Float32Array[][],
61	    parameters: Record<string, Float32Array>,
62	  ): boolean;
63	}
64	declare function registerProcessor(
65	  name: string,
66	  ctor: typeof AudioWorkletProcessor,
67	): void;
68	
69	// ─── Per-Voice State (pre-allocated) ───
70	
71	type VoiceData = {
72	  osc1: PolyBLEPOsc;
73	  osc2: PolyBLEPOsc;
74	  ampEnv: ADSREnvelope;
75	  filterEnv: ADSREnvelope;
76	  filter: BiquadFilter;
77	  targetFreq: number;
78	  currentFreq: number;
79	  velocity: number;
80	};
81	
82	function createVoiceData(): VoiceData {
83	  return {
84	    osc1: createPolyBLEPOsc("saw"),
85	    osc2: createPolyBLEPOsc("saw"),
86	    ampEnv: createADSREnvelope(),
87	    filterEnv: createADSREnvelope(),
88	    filter: createBiquadFilter("lowpass"),
89	    targetFreq: 440,
90	    currentFreq: 440,
91	    velocity: 0,
92	  };
93	}
94	
95	/** Safe access to pre-allocated arrays */
96	function at<T>(arr: T[], i: number): T {
97	  const val = arr[i];
98	  if (val === undefined) throw new Error("Index out of bounds");
99	  return val;
100	}
101	
102	class SynthProcessor extends AudioWorkletProcessor {
103	  private allocator: VoiceAllocator;
104	  private voiceData: VoiceData[];
105	  private lfo1: LFO;
106	  private lfo2: LFO;
107	  private params: SynthParameterMap;
108	  // Pre-allocated ADSR params (S2-3: avoid per-quantum allocation)
109	  private ampParams: ADSRParams;
110	  private filterParams: ADSRParams;
111	  private alive = true;
112	
113	  // Modulation matrix (pre-allocated)
114	  private modRoutes: WorkletModRoute[] = [];
115	  private modSourceValues = new Float64Array(8); // Global source values
116	  private modAccGlobal: ModAccumulators = createModAccumulators();
117	  private modAccVoice: ModAccumulators = createModAccumulators();
118	
119	  constructor() {
120	    super();
121	
122	    this.allocator = createVoiceAllocator();
123	    this.voiceData = Array.from({ length: MAX_VOICES }, () =>
124	      createVoiceData(),
125	    );
126	    this.lfo1 = createLFO("sine");
127	    this.lfo2 = createLFO("sine");
128	    this.params = { ...DEFAULT_SYNTH_PARAMS };
129	    this.ampParams = { attack: 0, decay: 0, sustain: 0, release: 0 };
130	    this.filterParams = { attack: 0, decay: 0, sustain: 0, release: 0 };
131	
132	    this.port.onmessage = (e: MessageEvent) => {
133	      this.handleMessage(e.data as SynthVoiceCommand);
134	    };
135	  }
136	
137	  private handleMessage(cmd: SynthVoiceCommand): void {
138	    switch (cmd.type) {
139	      case "noteOn": {
140	        const legato = cmd.legato;
141	        const idx = this.allocator.noteOn(cmd.note, cmd.velocity, legato);
142	        const voice = at(
143	          this.allocator.voices as unknown[],
144	          idx,
145	        ) as (typeof this.allocator.voices)[number];
146	
147	        // If voice is stealing, don't touch oscillators/envelopes yet —
148	        // the old voice continues rendering during the 5ms crossfade.
149	        // The processor will apply the new note when steal completes.
150	        if (voice.state === "stealing") {
151	          return;
152	        }
153	
154	        this.applyNoteOn(idx, cmd.note, cmd.velocity, legato);
155	        break;
156	      }
157	
158	      case "noteOff": {
159	        const idx = this.allocator.noteOff(cmd.note);
160	        if (idx >= 0) {
161	          const vd = at(this.voiceData, idx);
162	          vd.ampEnv.release();
163	          vd.filterEnv.release();
164	        }
165	        break;
166	      }
167	
168	      case "allNotesOff":
169	        // S1-4: Must also update allocator state
170	        for (let i = 0; i < MAX_VOICES; i++) {
171	          const voice = at(
172	            this.allocator.voices as unknown[],
173	            i,
174	          ) as (typeof this.allocator.voices)[number];
175	          if (voice.state === "active") {
176	            (voice as { state: string }).state = "releasing";
177	          } else if (voice.state === "stealing") {
178	            // Cancel pending steal — clear pending note and release
179	            (voice as { state: string }).state = "releasing";
180	            (voice as { pendingNote: number }).pendingNote = -1;
181	            (voice as { pendingVelocity: number }).pendingVelocity = 0;
182	          }
183	          at(this.voiceData, i).ampEnv.release();
184	          at(this.voiceData, i).filterEnv.release();
185	        }
186	        break;
187	
188	      case "setParam":
189	        this.setParamValue(cmd.key, cmd.value);
190	        break;
191	
192	      case "setModRoutes":
193	        this.modRoutes = cmd.routes;
194	        break;
195	
196	      case "setModSource": {
197	        // Update global mod source values (aftertouch, modwheel, pitchbend)
198	        const srcKey = cmd.source as keyof typeof SOURCE_INDEX;
199	        if (srcKey in SOURCE_INDEX) {
200	          this.modSourceValues[SOURCE_INDEX[srcKey]] = cmd.value;
201	        }
202	        break;
203	      }
204	    }
205	  }
206	
207	  /** Apply a note-on to voice oscillators and envelopes */
208	  private applyNoteOn(
209	    idx: number,
210	    note: number,
211	    velocity: number,
212	    legato: boolean,
213	  ): void {
214	    const vd = at(this.voiceData, idx);
215	
216	    const baseFreq = midiToFreq(note);
217	    vd.targetFreq = baseFreq;
218	    vd.velocity = velocity / 127;
219	
220	    if (!legato || vd.currentFreq === 0) {
221	      vd.currentFreq = baseFreq;
222	    }
223	
224	    if (!legato) {
225	      vd.osc1.reset();
226	      vd.osc2.reset();
227	      vd.filter.reset();
228	    }
229	
230	    vd.osc1.type = this.params.osc1Type;
231	    vd.osc2.type = this.params.osc2Type;
232	    vd.filter.type = this.params.filterType;
233	
234	    vd.ampEnv.gate(legato);
235	    vd.filterEnv.gate(legato);
236	  }
237	
238	  private setParamValue(key: string, value: number): void {
239	    switch (key) {
240	      case "osc1Type":
241	        this.params.osc1Type = WAVEFORM_TYPES[Math.round(value)] ?? "saw";
242	        break;
243	      case "osc2Type":
244	        this.params.osc2Type = WAVEFORM_TYPES[Math.round(value)] ?? "saw";
245	        break;
246	      case "filterType": {
247	        const ft = FILTER_TYPES[Math.round(value)] ?? "lowpass";
248	        this.params.filterType = ft;
249	        for (let i = 0; i < MAX_VOICES; i++) {
250	          at(this.voiceData, i).filter.type = ft;
251	        }
252	        break;
253	      }
254	      case "lfo1Shape":
255	        this.params.lfo1Shape = LFO_SHAPES[Math.round(value)] ?? "sine";
256	        this.lfo1.shape = this.params.lfo1Shape;
257	        break;
258	      case "lfo2Shape":
259	        this.params.lfo2Shape = LFO_SHAPES[Math.round(value)] ?? "sine";
260	        this.lfo2.shape = this.params.lfo2Shape;
261	        break;
262	      default:
263	        (this.params as Record<string, unknown>)[key] = value;
264	        break;
265	    }
266	  }
267	
268	  process(
269	    _inputs: Float32Array[][],
270	    outputs: Float32Array[][],
271	    _parameters: Record<string, Float32Array>,
272	  ): boolean {
273	    const output = outputs[0];
274	    if (!output) return this.alive;
275	
276	    const outL = output[0];
277	    const outR = output[1] ?? output[0];
278	    if (!outL || !outR) return this.alive;
279	
280	    const numSamples = outL.length;
281	    const sr = sampleRate;
282	    const p = this.params;
283	
284	    // Update pre-allocated ADSR params in-place (S2-3)
285	    this.ampParams.attack = p.ampAttack;
286	    this.ampParams.decay = p.ampDecay;
287	    this.ampParams.sustain = p.ampSustain;
288	    this.ampParams.release = p.ampRelease;
289	
290	    this.filterParams.attack = p.filterAttack;
291	    this.filterParams.decay = p.filterDecay;
292	    this.filterParams.sustain = p.filterSustain;
293	    this.filterParams.release = p.filterRelease;
294	
295	    // Pre-compute control-rate values (constant across quantum)
296	    const osc1OctMul = Math.pow(2, p.osc1Octave);
297	    const osc1DetMul = Math.pow(2, p.osc1Detune / 1200);
298	    const osc2OctMul = Math.pow(2, p.osc2Octave);
299	    const osc2DetMul = Math.pow(2, p.osc2Detune / 1200);
300	
301	    // Per-voice source values (reused each voice iteration)
302	    const voiceSrcValues = new Float64Array(8);
303	
304	    for (let s = 0; s < numSamples; s++) {
305	      // LFO rates incorporate modulation from previous sample (1-sample delay, inaudible)
306	      const lfo1Rate = Math.max(0.01, p.lfo1Rate + this.modAccGlobal.lfo1Rate);
307	      const lfo2Rate = Math.max(0.01, p.lfo2Rate + this.modAccGlobal.lfo2Rate);
308	      const lfo1Val = this.lfo1.process(lfo1Rate, sr);
309	      const lfo2Val = this.lfo2.process(lfo2Rate, sr);
310	
311	      // Update global source values for modulation
312	      this.modSourceValues[SOURCE_INDEX.lfo1] = lfo1Val;
313	      this.modSourceValues[SOURCE_INDEX.lfo2] = lfo2Val;
314	
315	      // Compute global modulation (from non-per-voice sources)
316	      resetAccumulators(this.modAccGlobal);
317	      for (let ri = 0; ri < this.modRoutes.length; ri++) {
318	        const route = at(this.modRoutes as unknown[], ri) as WorkletModRoute;
319	        // Global sources: lfo1, lfo2, aftertouch, modWheel, pitchBend
320	        const si = route.sourceIdx;
321	        if (
322	          si === SOURCE_INDEX.lfo1 ||
323	          si === SOURCE_INDEX.lfo2 ||
324	          si === SOURCE_INDEX.aftertouch ||
325	          si === SOURCE_INDEX.modWheel ||
326	          si === SOURCE_INDEX.pitchBend
327	        ) {
328	          applyModRoute(
329	            this.modAccGlobal,
330	            this.modSourceValues,
331	            si,
332	            route.destIdx,
333	            route.amount,
334	            route.bipolar,
335	          );
336	        }
337	      }
338	
339	      let mixL = 0;
340	      let mixR = 0;
341	
342	      for (let vi = 0; vi < MAX_VOICES; vi++) {
343	        const voice = at(this.allocator.voices as unknown[], vi) as {
344	          state: string;
345	          stealFadeGain: number;
346	        };
347	
348	        // S2-5: Early idle check before any DSP work
349	        if (voice.state === "idle") continue;
350	
351	        const vd = at(this.voiceData, vi);
352	
353	        // Check if envelope finished release — mark idle before processing
354	        if (vd.ampEnv.stage === "idle" && voice.state === "releasing") {
355	          this.allocator.markIdle(vi);
356	          continue;
357	        }
358	
359	        // Pitch glide (R-STA-05)
360	        if (p.glideTime > 0 && vd.currentFreq !== vd.targetFreq) {
361	          const glideCoeff = 1 - Math.exp(-1 / (p.glideTime * sr));
362	          vd.currentFreq += glideCoeff * (vd.targetFreq - vd.currentFreq);
363	        } else {
364	          vd.currentFreq = vd.targetFreq;
365	        }
366	
367	        const baseFreq = vd.currentFreq;
368	
369	        // Filter envelope (must process every sample to advance state)
370	        const filterEnvVal = vd.filterEnv.process(this.filterParams, sr);
371	        // Amplitude envelope
372	        const ampLevel = vd.ampEnv.process(this.ampParams, sr);
373	
374	        // Compute per-voice modulation
375	        resetAccumulators(this.modAccVoice);
376	        if (this.modRoutes.length > 0) {
377	          // Set per-voice source values
378	          voiceSrcValues[SOURCE_INDEX.ampEnv] = ampLevel;
379	          voiceSrcValues[SOURCE_INDEX.filterEnv] = filterEnvVal;
380	          voiceSrcValues[SOURCE_INDEX.velocity] = vd.velocity;
381	
382	          for (let ri = 0; ri < this.modRoutes.length; ri++) {
383	            const route = at(
384	              this.modRoutes as unknown[],
385	              ri,
386	            ) as WorkletModRoute;
387	            const si = route.sourceIdx;
388	            // Per-voice sources: ampEnv, filterEnv, velocity
389	            if (
390	              si === SOURCE_INDEX.ampEnv ||
391	              si === SOURCE_INDEX.filterEnv ||
392	              si === SOURCE_INDEX.velocity
393	            ) {
394	              applyModRoute(
395	                this.modAccVoice,
396	                voiceSrcValues,
397	                si,
398	                route.destIdx,
399	                route.amount,
400	                route.bipolar,
401	              );
402	            }
403	          }
404	        }
405	
406	        // Combined modulation (global + per-voice)
407	        const modPitchOsc1 =
408	          this.modAccGlobal.osc1Pitch + this.modAccVoice.osc1Pitch;
409	        const modPitchOsc2 =
410	          this.modAccGlobal.osc2Pitch + this.modAccVoice.osc2Pitch;
411	        const modFilterCutoff =
412	          this.modAccGlobal.filterCutoff + this.modAccVoice.filterCutoff;
413	        const modFilterReso =
414	          this.modAccGlobal.filterResonance + this.modAccVoice.filterResonance;
415	        const modAmpLevel =
416	          this.modAccGlobal.ampLevel + this.modAccVoice.ampLevel;
417	        const modOscMix = this.modAccGlobal.oscMix + this.modAccVoice.oscMix;
418	
419	        // Pitch modulation (scaled to semitones, max +/-24)
420	        const pitchMod1 = modPitchOsc1 * 24;
421	        const pitchMod2 = modPitchOsc2 * 24;
422	        const pitchMult1 = Math.pow(2, pitchMod1 / 12);
423	        const pitchMult2 = Math.pow(2, pitchMod2 / 12);
424	
425	        const freq1 = baseFreq * osc1OctMul * osc1DetMul * pitchMult1;
426	        const freq2 = baseFreq * osc2OctMul * osc2DetMul * pitchMult2;
427	
428	        const osc1Out = vd.osc1.next(freq1, sr) * p.osc1Level;
429	        const osc2Out = vd.osc2.next(freq2, sr) * p.osc2Level;
430	
431	        // Osc mix: without modulation, both oscs play at full level.
432	        // oscMix modulation crossfades: negative = more osc1, positive = more osc2
433	        const osc1Gain = Math.max(0, Math.min(1, 1 - modOscMix));
434	        const osc2Gain = Math.max(0, Math.min(1, 1 + modOscMix));
435	        let sample = osc1Out * osc1Gain + osc2Out * osc2Gain;
436	
437	        // Control-rate filter coefficients: recompute once per block per voice
438	        if (s === 0) {
439	          // Filter cutoff modulation (in semitones)
440	          const cutoffModSt =
441	            filterEnvVal * p.filterEnvDepth + modFilterCutoff * 60;
442	          const modulatedCutoff =
443	            p.filterCutoff * Math.pow(2, cutoffModSt / 12);
444	          const clampedCutoff = Math.min(
445	            Math.max(modulatedCutoff, 20),
446	            sr / 2 - 100,
447	          );
448	          // Filter resonance modulation
449	          const modulatedReso = Math.max(
450	            0.5,
451	            Math.min(20, p.filterResonance + modFilterReso * 10),
452	          );
453	          computeBiquadCoeffs(
454	            p.filterType,
455	            clampedCutoff,
456	            modulatedReso,
457	            sr,
458	            vd.filter.coeffs,
459	          );
460	        }
461	
462	        sample = vd.filter.process(sample);
463	
464	        // Amplitude modulation: base envelope * (1 + mod offset)
465	        const ampMod = Math.max(0, 1 + modAmpLevel);
466	
467	        // Velocity -> amplitude
468	        const velAmp = 0.5 + vd.velocity * 0.5;
469	
470	        sample *= ampLevel * ampMod * velAmp * p.masterGain;
471	
472	        // S1-2: Apply steal crossfade gain to old voice audio
473	        if (voice.state === "stealing") {
474	          sample *= voice.stealFadeGain;
475	        }
476	
477	        mixL += sample;
478	        mixR += sample;
479	      }
480	
481	      // Process steal fades and get completed steals
482	      const completed = this.allocator.processStealFade(sr);
483	
484	      // S1-3: Apply pending notes for voices that completed steal crossfade
485	      for (let ci = 0; ci < completed.count; ci++) {
486	        const completedIdx = completed.data[ci];
487	        if (completedIdx !== undefined) {
488	          const voice = at(
489	            this.allocator.voices as unknown[],
490	            completedIdx,
491	          ) as {
492	            note: number;
493	            velocity: number;
494	          };
495	          this.applyNoteOn(completedIdx, voice.note, voice.velocity, false);
496	        }
497	      }
498	
499	      outL[s] = mixL;
500	      outR[s] = mixR;
501	    }
502	
503	    return this.alive;
504	  }
505	}
506	
