1	/**
2	 * SynthInstrument: main-thread controller for the synth AudioWorklet.
3	 * Creates AudioWorkletNode, sends voice commands, manages parameters,
4	 * connects output to mixer channel strip.
5	 *
6	 * R-EVT-08: Real-time parameter changes via MessagePort.
7	 */
8	
9	import type { SynthVoiceCommand, SynthParameterMap } from "./synth-types";
10	import {
11	  DEFAULT_SYNTH_PARAMS,
12	  WAVEFORM_TYPES,
13	  FILTER_TYPES,
14	  LFO_SHAPES,
15	} from "./synth-types";
16	import type { MixerEngine } from "@audio/mixer/types";
17	import type { WorkletModRoute } from "./modulation-engine";
18	
19	export type SynthInstrument = {
20	  /** The audio output node — connect to mixer channel strip. */
21	  readonly output: AudioNode;
22	  /** Current parameter values. */
23	  readonly params: Readonly<SynthParameterMap>;
24	  /** Send a note-on to the synth. */
25	  noteOn(note: number, velocity: number, legato?: boolean): void;
26	  /** Send a note-off to the synth. */
27	  noteOff(note: number): void;
28	  /** Release all notes. */
29	  allNotesOff(): void;
30	  /** Set a synth parameter (forwarded to worklet). */
31	  setParam<K extends keyof SynthParameterMap>(
32	    key: K,
33	    value: SynthParameterMap[K],
34	  ): void;
35	  /** Send modulation routes to the worklet. */
36	  setModRoutes(routes: WorkletModRoute[]): void;
37	  /** Set a modulation source value (aftertouch, modWheel, pitchBend). */
38	  setModSource(source: string, value: number): void;
39	  /** Connect to a mixer channel. */
40	  connectToMixer(mixer: MixerEngine, trackId: string): void;
41	  /** Disconnect from mixer. */
42	  disconnectFromMixer(mixer: MixerEngine, trackId: string): void;
43	  /** Clean up all resources. */
44	  dispose(): void;
45	};
46	
47	/** URL for the worklet processor module */
48	const PROCESSOR_URL = new URL("./synth-processor.ts", import.meta.url);
49	
50	/**
51	 * Create a SynthInstrument connected to the given AudioContext.
52	 * Must call `audioCtx.audioWorklet.addModule()` first via loadWorkletModule().
53	 */
54	export async function createSynthInstrument(
55	  ctx: AudioContext,
56	): Promise<SynthInstrument> {
57	  // Load the worklet module
58	  await ctx.audioWorklet.addModule(PROCESSOR_URL.href);
59	
60	  const node = new AudioWorkletNode(ctx, "synth-processor", {
61	    numberOfInputs: 0,
62	    numberOfOutputs: 1,
63	    outputChannelCount: [2],
64	  });
65	
66	  const params: SynthParameterMap = { ...DEFAULT_SYNTH_PARAMS };
67	
68	  function postCommand(cmd: SynthVoiceCommand): void {
69	    node.port.postMessage(cmd);
70	  }
71	
72	  const instrument: SynthInstrument = {
73	    output: node,
74	    params,
75	
76	    noteOn(note: number, velocity: number, legato = false): void {
77	      postCommand({ type: "noteOn", note, velocity, legato });
78	    },
79	
80	    noteOff(note: number): void {
81	      postCommand({ type: "noteOff", note });
82	    },
83	
84	    allNotesOff(): void {
85	      postCommand({ type: "allNotesOff" });
86	    },
87	
88	    setParam<K extends keyof SynthParameterMap>(
89	      key: K,
90	      value: SynthParameterMap[K],
91	    ): void {
92	      (params as Record<string, unknown>)[key] = value;
93	
94	      // Map enum types to numeric index for the worklet
95	      let numericValue: number;
96	      if (typeof value === "string") {
97	        // Lookup string in appropriate type array
98	        switch (key) {
99	          case "osc1Type":
100	          case "osc2Type":
101	            numericValue = WAVEFORM_TYPES.indexOf(
102	              value as (typeof WAVEFORM_TYPES)[number],
103	            );
104	            break;
105	          case "filterType":
106	            numericValue = FILTER_TYPES.indexOf(
107	              value as (typeof FILTER_TYPES)[number],
108	            );
109	            break;
110	          case "lfo1Shape":
111	          case "lfo2Shape":
112	            numericValue = LFO_SHAPES.indexOf(
113	              value as (typeof LFO_SHAPES)[number],
114	            );
115	            break;
116	          default:
117	            numericValue = 0;
118	        }
119	      } else {
120	        numericValue = value;
121	      }
122	
123	      postCommand({
124	        type: "setParam",
125	        key: key as string,
126	        value: numericValue,
127	      });
128	    },
129	
130	    setModRoutes(routes: WorkletModRoute[]): void {
131	      postCommand({ type: "setModRoutes", routes });
132	    },
133	
134	    setModSource(source: string, value: number): void {
135	      postCommand({ type: "setModSource", source, value });
136	    },
137	
138	    connectToMixer(mixer: MixerEngine, trackId: string): void {
139	      const strip = mixer.getOrCreateStrip(trackId);
140	      node.connect(strip.inputGain);
141	    },
142	
143	    disconnectFromMixer(_mixer: MixerEngine, _trackId: string): void {
144	      node.disconnect();
145	    },
146	
147	    dispose(): void {
148	      node.disconnect();
149	      node.port.close();
150	    },
151	  };
152	
153	  return instrument;
154	}
