1	/**
2	 * LFO (Low Frequency Oscillator) for modulation.
3	 * Supports sine, square, triangle, and sample-and-hold shapes.
4	 * Output range: [-1, 1], scaled by depth at the modulation destination.
5	 */
6	
7	export type LFOShape = "sine" | "square" | "triangle" | "sample-and-hold";
8	
9	/**
10	 * Stateful LFO. Call `process()` once per sample.
11	 * Zero-allocation in the hot path.
12	 */
13	export type LFO = {
14	  shape: LFOShape;
15	  /** Advance one sample. Returns output in [-1, 1]. */
16	  process(rate: number, sampleRate: number): number;
17	  /** Reset phase. */
18	  reset(): void;
19	};
20	
21	/** Deterministic xorshift32 PRNG (zero-allocation, no Math.random). */
22	function xorshift32(seed: number): number {
23	  let x = seed;
24	  x ^= x << 13;
25	  x ^= x >>> 17;
26	  x ^= x << 5;
27	  return x;
28	}
29	
30	export function createLFO(shape: LFOShape = "sine"): LFO {
31	  let phase = 0;
32	  let shValue = 0; // Sample-and-hold current value
33	  let prevPhase = 0; // For detecting S&H trigger
34	  let prngState = 123456789; // PRNG seed
35	
36	  const lfo: LFO = {
37	    shape,
38	
39	    process(rate: number, sampleRate: number): number {
40	      const dt = rate / sampleRate;
41	      let out: number;
42	
43	      switch (lfo.shape) {
44	        case "sine":
45	          out = Math.sin(2 * Math.PI * phase);
46	          break;
47	
48	        case "square":
49	          out = phase < 0.5 ? 1 : -1;
50	          break;
51	
52	        case "triangle":
53	          // Ramp 0->1->0 mapped to -1->1->-1
54	          out = phase < 0.5 ? 4 * phase - 1 : 3 - 4 * phase;
55	          break;
56	
57	        case "sample-and-hold":
58	          // New deterministic pseudo-random value each cycle
59	          if (phase < prevPhase) {
60	            prngState = xorshift32(prngState);
61	            // Map signed int32 to [-1, 1) via division by 2^31
62	            shValue = prngState / 2147483648;
63	          }
64	          out = shValue;
65	          break;
66	
67	        default:
68	          out = 0;
69	      }
70	
71	      prevPhase = phase;
72	      phase += dt;
73	      if (phase >= 1) phase -= 1;
74	
75	      return out;
76	    },
77	
78	    reset(): void {
79	      phase = 0;
80	      prevPhase = 0;
81	      shValue = 0;
82	      prngState = 123456789;
83	    },
84	  };
85	
86	  return lfo;
87	}
