2	import { useDawStore } from "@state/store";
3	import { useEffectsStore } from "@state/effects";
4	import type { SessionStorage } from "./session-storage";
5	import { createSaveQueue } from "./save-queue";
6	import { createAutoSave } from "./auto-save";
7	import { recoverSession } from "./session-recovery";
8	import { SESSION_VERSION } from "./session-schema";
9	import type { SessionSchema } from "./session-schema";
10	
11	// Stored meta from the loaded session, preserved across auto-saves
12	let sessionMeta: { name: string; createdAt: number } = {
13	  name: "Untitled",
14	  createdAt: Date.now(),
15	};
16	
17	function storeToSession(): SessionSchema {
18	  const state = useDawStore.getState();
19	  const effectsState = useEffectsStore.getState();
20	
21	  // Convert effects store to session schema format
22	  const effects = Object.entries(effectsState.trackEffects).map(
23	    ([trackId, slots]) => ({
24	      trackId,
25	      slots: slots.map((s) => ({
26	        id: s.id,
27	        typeId: s.typeId,
28	        bypassed: s.bypassed,
29	        params: { ...s.params },
30	      })),
31	    }),
32	  );
33	
34	  return {
35	    version: SESSION_VERSION,
36	    meta: {
37	      name: sessionMeta.name,
38	      createdAt: sessionMeta.createdAt,
39	      updatedAt: Date.now(),
40	    },
41	    transport: {
42	      bpm: state.bpm,
43	      loopEnabled: state.loopEnabled,
44	      loopStart: state.loopStart,
45	      loopEnd: state.loopEnd,
46	    },
47	    tracks: state.tracks.map((t) => ({ ...t })),
48	    clips: Object.values(state.clips),
49	    mixer: { masterVolume: state.masterVolume },
50	    effects: effects.length > 0 ? effects : undefined,
51	  };
52	}
