          si === SOURCE_INDEX.lfo1 ||
          si === SOURCE_INDEX.lfo2 ||
          si === SOURCE_INDEX.aftertouch ||
          si === SOURCE_INDEX.modWheel ||
          si === SOURCE_INDEX.pitchBend
