        const pitchMod1 = modPitchOsc1 * 24;
        const pitchMod2 = modPitchOsc2 * 24;
        const pitchMult1 = Math.pow(2, pitchMod1 / 12);
        const pitchMult2 = Math.pow(2, pitchMod2 / 12);

