type Props = {
  trackId: string;
};

const EMPTY_ROUTES: readonly ModRoute[] = [];

const BORDER = `${String(tokens.border.width)}px solid ${tokens.color.gray700}`;

const LABEL_STYLE: React.CSSProperties = {
  fontFamily: tokens.font.mono,
  fontSize: tokens.text.xs,
  color: tokens.color.gray300,
  textTransform: "uppercase",
  letterSpacing: "0.1em",
};

// Cable colors per source (cycle through for visual distinction)
const SOURCE_COLORS: Record<ModSource, string> = {
  lfo1: tokens.color.blue,
  lfo2: tokens.color.pink,
  ampEnv: tokens.color.amber,
  filterEnv: tokens.color.green,
  velocity: "#ff6600",
  aftertouch: "#cc44ff",
  modWheel: "#00ccff",
  pitchBend: "#ff4488",
};

function Port({
  testId,
  color,
  onMouseDown,
  onMouseUp,
}: {
  testId: string;
  color: string;
  onMouseDown?: () => void;
  onMouseUp?: () => void;
}): React.JSX.Element {
  return (
    <div
      data-testid={testId}
      onMouseDown={onMouseDown}
      onMouseUp={onMouseUp}
      style={{
        width: 12,
        height: 12,
        borderRadius: "50%",
        border: `2px solid ${color}`,
        backgroundColor: tokens.color.gray900,
        cursor: "pointer",
        flexShrink: 0,
      }}
    />
  );
}

