1	import { useEffect, useRef, useState, useCallback, useMemo } from "react";
2	import { useDawStore } from "@state/store";
3	import { useEffectsStore } from "@state/effects";
4	import type { SessionStorage } from "./session-storage";
5	import { createSaveQueue } from "./save-queue";
6	import { createAutoSave } from "./auto-save";
7	import { recoverSession } from "./session-recovery";
8	import { SESSION_VERSION } from "./session-schema";
9	import type { SessionSchema } from "./session-schema";
10	
11	// Stored meta from the loaded session, preserved across auto-saves
12	let sessionMeta: { name: string; createdAt: number } = {
13	  name: "Untitled",
14	  createdAt: Date.now(),
15	};
16	
17	function storeToSession(): SessionSchema {
18	  const state = useDawStore.getState();
19	  const effectsState = useEffectsStore.getState();
20	
21	  // Convert effects store to session schema format
22	  const effects = Object.entries(effectsState.trackEffects).map(
23	    ([trackId, slots]) => ({
24	      trackId,
25	      slots: slots.map((s) => ({
26	        id: s.id,
27	        typeId: s.typeId,
28	        bypassed: s.bypassed,
29	        params: { ...s.params },
30	      })),
31	    }),
32	  );
33	
34	  return {
35	    version: SESSION_VERSION,
36	    meta: {
37	      name: sessionMeta.name,
38	      createdAt: sessionMeta.createdAt,
39	      updatedAt: Date.now(),
40	    },
41	    transport: {
42	      bpm: state.bpm,
43	      loopEnabled: state.loopEnabled,
44	      loopStart: state.loopStart,
45	      loopEnd: state.loopEnd,
46	    },
47	    tracks: state.tracks.map((t) => ({ ...t })),
48	    clips: Object.values(state.clips),
49	    mixer: { masterVolume: state.masterVolume },
50	    effects: effects.length > 0 ? effects : undefined,
51	  };
52	}
53	
54	export function hydrateStore(session: SessionSchema): void {
55	  sessionMeta = {
56	    name: session.meta.name,
57	    createdAt: session.meta.createdAt,
58	  };
59	  const clips: Record<string, (typeof session.clips)[number]> = {};
60	  for (const clip of session.clips) {
61	    clips[clip.id] = clip;
62	  }
63	
64	  useDawStore.setState({
65	    bpm: session.transport.bpm,
66	    loopEnabled: session.transport.loopEnabled,
67	    loopStart: session.transport.loopStart,
68	    loopEnd: session.transport.loopEnd,
69	    tracks: session.tracks,
70	    clips,
71	    masterVolume: session.mixer.masterVolume,
72	  });
73	
74	  // Restore effects state (always clear first to avoid stale ghost inserts)
75	  const trackEffects: Record<
76	    string,
77	    readonly {
78	      id: string;
79	      typeId: string;
80	      bypassed: boolean;
81	      params: Record<string, number>;
82	    }[]
83	  > = {};
84	  if (session.effects) {
85	    for (const entry of session.effects) {
86	      trackEffects[entry.trackId] = entry.slots;
87	    }
88	  }
89	  useEffectsStore.setState({ trackEffects });
90	}
91	
92	type SessionPersistenceResult = {
93	  saving: boolean;
94	  dirty: boolean;
95	  saveNow: () => Promise<void>;
96	  recoveryWarnings: string[];
97	};
98	
99	export function useSessionPersistence(
100	  storage: SessionStorage,
101	): SessionPersistenceResult {
102	  const [recoveryWarnings, setRecoveryWarnings] = useState<string[]>([]);
103	  const [saving, setSaving] = useState(false);
104	  const loadedRef = useRef(false);
105	
106	  const saveQueue = useMemo(() => createSaveQueue(storage), [storage]);
107	
108	  const autoSave = useMemo(
109	    () => createAutoSave(() => JSON.stringify(storeToSession()), saveQueue),
110	    [saveQueue],
111	  );
112	
113	  // Load session from storage on mount (draft-first for crash safety)
114	  useEffect(() => {
115	    if (loadedRef.current) return;
116	    loadedRef.current = true;
117	
118	    void (async (): Promise<void> => {
119	      // Check draft first — a crash between putDraft and putCurrent
120	      // means the draft is the most recent write attempt
121	      const draft = await storage.getDraft();
122	      const raw = draft ?? (await storage.getCurrent());
