  // Restore effects state (always clear first to avoid stale ghost inserts)
  const trackEffects: Record<
    string,
    readonly {
      id: string;
      typeId: string;
      bypassed: boolean;
      params: Record<string, number>;
    }[]
  > = {};
  if (session.effects) {
    for (const entry of session.effects) {
      trackEffects[entry.trackId] = entry.slots;
    }
  }
  useEffectsStore.setState({ trackEffects });

  // Restore modulation state
  const matrices: Record<string, { routes: readonly { id: string; source: string; destination: string; amount: number; bipolar: boolean }[] }> = {};
